#!/usr/bin/env bash
# =============================================================================
# apply-hud-opacity.sh
#
# Applies the HUD opacity slider patch to an Arx Libertatis 1.2.1 source tree.
#
# Generated by Claude Sonnet 4.6 (https://www.anthropic.com/claude)
# running as Claude Code (https://claude.ai/code).
#
# Usage:
#   bash apply-hud-opacity.sh /path/to/ArxLibertatis-1.2.1
#
# What this script does:
#   1. Adds `float hudOpacity` to the Config interface struct (Config.h)
#   2. Adds default value, config key, writer, and clamped reader (Config.cpp)
#   3. Adds a "HUD Opacity" slider to the Interface options page (MainMenu.cpp)
#   4. Adds hudAlpha() helper and OpModulate bracket to the HUD render path (Hud.cpp)
#   5. Applies opacity to the HudIconBase draw function (HudCommon.cpp)
#
# The patch is equivalent to arx-hud-opacity.patch but self-documenting.
# Requires: python3 (for reliable multi-line string replacement)
#
# =============================================================================

set -euo pipefail

# ---------------------------------------------------------------------------
# Argument handling
# ---------------------------------------------------------------------------

if [ $# -ne 1 ]; then
    echo "Usage: $0 /path/to/ArxLibertatis-1.2.1"
    exit 1
fi

ROOT="$1"
SRC="$ROOT/src"

if [ ! -f "$SRC/core/Config.h" ]; then
    echo "ERROR: $SRC/core/Config.h not found — is '$ROOT' the correct source root?"
    exit 1
fi

echo "=== Arx Libertatis HUD opacity patch ==="
echo "Source root: $ROOT"
echo ""

# ---------------------------------------------------------------------------
# Helper: apply a Python string replacement to a file.
# Exits non-zero if the old string is not found (safety check).
# ---------------------------------------------------------------------------

replace() {
    local FILE="$1"
    # old string is read from fd 3, new string from fd 4 via process substitution
    python3 - "$FILE" <<'PYEOF'
import sys

filepath = sys.argv[1]
with open(filepath, 'r') as f:
    content = f.read()

# old and new are passed via environment variables set by the caller
import os
old = os.environ['OLD']
new = os.environ['NEW']

if old not in content:
    print(f"ERROR: expected string not found in {filepath}", file=sys.stderr)
    print(f"  Looking for: {repr(old[:120])}", file=sys.stderr)
    sys.exit(1)

content = content.replace(old, new, 1)
with open(filepath, 'w') as f:
    f.write(content)
PYEOF
}

# =============================================================================
# CHANGE 1 — src/core/Config.h
#
# Add `float hudOpacity` to the Config::interface sub-struct, immediately
# after `hudScaleInteger`. This is the in-memory storage for the setting.
# =============================================================================

echo "[1/5] Config.h — adding float hudOpacity to interface struct"

export OLD='		float hudScale;
		bool hudScaleInteger;
		float bookScale;'

export NEW='		float hudScale;
		bool hudScaleInteger;
		float hudOpacity;
		float bookScale;'

replace "$SRC/core/Config.h"
echo "      OK"

# =============================================================================
# CHANGE 2 — src/core/Config.cpp  (four sub-changes)
#
# Config.cpp has three namespaces (Default, Key) and two functions (save,
# init) that all need to know about the new key.
# =============================================================================

echo "[2/5] Config.cpp — default value, key name, writer, reader"

# --- 2a: Default value ---
# The default MUST be 1.0f (fully opaque) so existing installs are unaffected.
# This value is used when hud_opacity is absent from cfg.ini (i.e. on first
# launch after the patch, before the user ever opens Options).

export OLD='	hudScale = 0.5f,
	bookScale = 1.f,'

export NEW='	hudScale = 0.5f,
	hudOpacity = 1.f,
	bookScale = 1.f,'

replace "$SRC/core/Config.cpp"

# --- 2b: Config key string ---
# This is the key name written to and read from cfg.ini.
# Snake_case, consistent with all other keys in this file.

export OLD='	hudScale = "hud_scale",
	hudScaleInteger = "hud_scale_integer",
	bookScale = "book_scale",'

export NEW='	hudScale = "hud_scale",
	hudScaleInteger = "hud_scale_integer",
	hudOpacity = "hud_opacity",
	bookScale = "book_scale",'

replace "$SRC/core/Config.cpp"

# --- 2c: Writer (Config::save) ---
# Without this, the setting is never saved to cfg.ini and resets on every launch.

export OLD='	writer.writeKey(Key::hudScale, interface.hudScale);
	writer.writeKey(Key::hudScaleInteger, interface.hudScaleInteger);
	writer.writeKey(Key::bookScale, interface.bookScale);'

export NEW='	writer.writeKey(Key::hudScale, interface.hudScale);
	writer.writeKey(Key::hudScaleInteger, interface.hudScaleInteger);
	writer.writeKey(Key::hudOpacity, interface.hudOpacity);
	writer.writeKey(Key::bookScale, interface.bookScale);'

replace "$SRC/core/Config.cpp"

# --- 2d: Reader (Config::init) ---
# Reads the key from cfg.ini (using the default if absent), then clamps it
# to [0, 1]. Clamping is essential — every float key in this file is clamped
# to prevent out-of-range values from a hand-edited cfg.ini.

export OLD='	interface.hudScaleInteger = reader.getKey(Section::Interface, Key::hudScaleInteger, Default::hudScaleInteger);
	float bookScale = reader.getKey(Section::Interface, Key::bookScale, Default::bookScale);'

export NEW='	interface.hudScaleInteger = reader.getKey(Section::Interface, Key::hudScaleInteger, Default::hudScaleInteger);
	float hudOpacity = reader.getKey(Section::Interface, Key::hudOpacity, Default::hudOpacity);
	interface.hudOpacity = glm::clamp(hudOpacity, 0.f, 1.f);
	float bookScale = reader.getKey(Section::Interface, Key::bookScale, Default::bookScale);'

replace "$SRC/core/Config.cpp"
echo "      OK"

# =============================================================================
