# =============================================================================

echo "[3/5] MainMenu.cpp — HUD Opacity slider widget and callback"

# --- 3a: Slider widget ---
# Inserted between the hudScale slider block and the hudScaleInteger checkbox.
#
# Notes on implementation choices:
#   - getLocalised(..., "HUD Opacity"): two-arg form returns the fallback when
#     the key is absent. Since we don't modify .pak files, the key is always
#     absent and "HUD Opacity" is always shown.
#   - setValue(int(config.interface.hudOpacity * 10.f)): the SliderWidget
