# =============================================================================
# CHANGE 4 — src/gui/Hud.cpp  (multiple sub-changes)
#
# This is the render path. Two concepts:
#
# A) hudAlpha() helper: scales vertex alpha by hud_opacity. Applied to every
#    EERIEDrawBitmap color argument inside HUD draw functions.
#
# B) OpModulate bracket: THE critical fix.
#
#    Arx's OpenGL texture stage defaults to GL_COMBINE_ALPHA = GL_REPLACE,
#    which means fragment alpha = texture alpha, ignoring vertex alpha entirely.
#    This is a known deviation from the GL default (see the TODO comment in
#    GLTextureStage.cpp). Without fixing this, hudAlpha() has zero effect.
#
#    The fix: wrap all HUD draws with setAlphaOp(OpModulate), which switches
#    the formula to: fragment_alpha = texture_alpha * vertex_alpha.
#    With vertex_alpha = hud_opacity * 255, this gives:
#      fragment_alpha = texture_alpha * hud_opacity
#    At hud_opacity=1.0: identical to vanilla. At 0.5: half opacity.
#
#    The bracket is restored to OpSelectArg1 at the end of HudRoot::draw()
#    so nothing outside the HUD is affected.
#
# =============================================================================

echo "[4/5] Hud.cpp — hudAlpha() helper, OpModulate bracket, draw-call changes"

# --- 4a: hudAlpha() helper ---
# Inserted after the indicatorHorizSpacing constant, before the first class.
# Static (file-local) — not needed outside Hud.cpp.
# Reads config directly; no caching needed (float field access is trivially cheap).

export OLD='static const int indicatorVertSpacing = 30;
static const int indicatorHorizSpacing = 20;'

export NEW='static const int indicatorVertSpacing = 30;
static const int indicatorHorizSpacing = 20;

// Scale vertex alpha by HUD opacity. Works for all blend modes once OpModulate is active.
static Color hudAlpha(Color c) {
	return Color(c.r, c.g, c.b, u8(float(c.a) * config.interface.hudOpacity));
}'

replace "$SRC/gui/Hud.cpp"

# --- 4b: HitStrengthGauge::draw ---
