export NEW='		EERIEDrawBitmap(m_rect, 0.0001f, m_fullTex, hudAlpha(Color::gray(m_intensity)));
	}

	EERIEDrawBitmap(m_rect, 0.0001f, m_emptyTex, hudAlpha(Color::white));

